"""
MKT Christ Commentary — 1 Kings chapters 10–11
Run: python3 scripts/zc-christ-1kings-10-11.py

Source data used:
- data/interlinear/1kings.json
- data/translation/draft/mediating/1kings.json (MKT text)
- data/commentary/mkt-christ/1kings.json (existing entries to carry forward)

Key decisions in this range:
- Ch. 10 (Queen of Sheba, Solomon's wealth): treated primarily as "type/shadow" with
  Matt 12:42 / Luke 11:31 as the authoritative NT key ("something greater than Solomon is here")
- The 666 talents of gold (v14): noted as the numeric peak of Solomon's glory, not mapped
  to Rev 13:18 (the NT use is a different context; the connection is historically popular
  but exegetically speculative)
- Ch. 11 (apostasy, division announced): the Davidic "lamp" (v36) is classified "direct"
  via Ps 132:17 and Luke 1:69; "not forever" (v39) is classified "shadow" of restoration
- Solomon's violation of Deut 17:14-20 (multiplying wives, horses, gold) runs throughout
  both chapters as the structural reason for the fall
- Terminology follows existing 1 Kings christ entries: YHWH (not "the LORD" in Hebrew
  citation context), "the human king / the ideal king / the divine King" pattern
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

KINGS1 = {
  "10": {
    "1": '<p>A type: the queen of Sheba comes from the ends of the earth to test (<em>lᵉnassōt</em>, H5254 — to test, prove) Solomon\'s wisdom gained in connection with the name of YHWH. Jesus cites this episode as a direct typological precedent in Matt 12:42 / Luke 11:31: "The queen of the South will rise at the judgment with this generation and condemn it, for she came from the ends of the earth to hear the wisdom of Solomon, and behold, something greater than Solomon is here." The Solomonic wisdom episode establishes the type — a Gentile ruler drawn irresistibly to divine wisdom — which Christ then exceeds in person.</p>',
    "2": '<p>A shadow: the queen\'s journey to Jerusalem with camels bearing spices, gold, and precious stones anticipates the pilgrimage of the nations to Zion described in Isaiah 60:3-6 ("nations shall come to your light, kings to the brightness of your rising... they shall bring gold and frankincense"). The wealth and the questions she brings represent the Gentile world\'s deepest longings — wisdom and resources — placed before the one whom God has blessed. The pattern reaches its fulfillment in the Magi of Matt 2 and ultimately in Rev 21:24-26 (the nations bringing their glory into the New Jerusalem).</p>',
    "3": '<p>A shadow: Solomon answers all her questions — "there was nothing hidden from the king that he could not tell her." The completeness of Solomonic wisdom points forward to Christ in whom "are hidden all the treasures of wisdom and knowledge" (Col 2:3). Where Solomon\'s wisdom is derived (God-given, 1 Kgs 3:12) and therefore exhaustible, Christ\'s wisdom is constitutive: he is the wisdom of God (1 Cor 1:24). The contrast Solomon/Christ is the NT\'s explicit theology in Matt 12:42.</p>',
    "4": '<p>A shadow: the queen witnesses all Solomon\'s wisdom "and the palace he had built." The pairing of wisdom and the built temple-palace complex echoes Proverbs 9:1 ("Wisdom has built her house"). Solomon\'s establishment of both the house of YHWH and his own palace is the OT\'s closest picture of the divine wisdom made architecturally present; it shadows the one of whom John says "the Word became flesh and dwelt (<em>eskēnōsen</em>) among us" — God building his own dwelling in human form (John 1:14).</p>',
    "5": '<p>A shadow: the queen is left breathless (<em>wᵉlōʾ-hāyāh bāh rûaḥ</em>, "there was no spirit left in her") by the sight of Solomon\'s glory. The encounter with divine wisdom and glory is overwhelming to the human visitor. The same response is promised to those who see the glory of Christ: "when he appears, we shall be like him" (1 John 3:2), yet in the meantime the encounter with divine holiness is humbling (Isa 6:5; Rev 1:17). The queen\'s speechlessness before Solomon\'s lesser glory is a shadow of the creature\'s response to the full manifestation of God in Christ.</p>',
    "6": '<p>A theme: "The report I heard in my own country about your deeds and your wisdom was true." The theme of a reliable report about a distant king whose glory exceeds all rumor recurs in the NT\'s theology of the gospel as proclamation: "How will they hear without someone preaching?" (Rom 10:14-15). The queen\'s acknowledgment that the report was true — even underestimated — anticipates the dynamic where the witness of the church carries an accurate but incomplete account of Christ\'s glory until he is seen face to face.</p>',
    "7": '<p>A theme: "I did not believe the reports until I came and saw with my own eyes. And even now the half was not told me." The gap between report and presence, between second-hand testimony and first-hand encounter, is a recurring NT theme: "Blessed are those who have not seen and yet have believed" (John 20:29). The queen had only report; she came and saw and was overwhelmed. The eschatological promise is that what believers now receive as testimony ("we have seen and bear witness," 1 John 1:2) will be exceeded by the direct sight promised at Christ\'s return.</p>',
    "8": '<p>A theme: "How fortunate are your men! How fortunate are these servants who stand before you continually and hear your wisdom!" The blessedness of those in continual proximity to divine wisdom is the beatitude of the Solomonic court. Jesus applies a parallel beatitude to his own disciples in Matt 13:16-17: "Blessed are your eyes, for they see, and your ears, for they hear. Truly I say to you, many prophets and righteous people longed to see what you see, and did not see it." The queen pronounces Solomonic beatitude from the outside; Jesus pronounces Christological beatitude on those who stand before him.</p>',
    "9": '<p>A revelation of God: a Gentile queen praises YHWH — "Praise the LORD your God, who delighted in you and set you on the throne of Israel!" Her theological interpretation of Solomon\'s elevation is correct: YHWH\'s love for Israel is the reason he raised up this king. The NT carries this structure forward: the exaltation of Jesus to God\'s right hand is YHWH\'s demonstration of love for humanity (Acts 2:36; Phil 2:9-11). Even a pagan witness, when confronted with genuine Solomonic glory, is moved to attribute it to Israel\'s God — a pattern fulfilled when "every tongue confesses that Jesus Christ is Lord, to the glory of God the Father" (Phil 2:11).</p>',
    "10": '<p>A shadow: the queen gives Solomon 120 talents of gold and abundant spices — the gifts of a Gentile ruler to Israel\'s anointed king. This establishes the OT pattern of Gentile tribute to the Davidic throne that Isaiah 60 develops into an eschatological vision of all nations bringing their wealth to Zion. The Magi\'s gold, frankincense, and myrrh (Matt 2:11) are the NT\'s first fulfillment of this pattern; Rev 21:24-26 describes its final form. The queen\'s gift begins a typological sequence that ends at the throne of the Lamb.</p>',
    "11": '<p>A shadow: the almugwood brought from Ophir along with gold and precious stones — all for the temple and its music. The beauty and richness of material creation consecrated for worship is a consistent OT shadow of the eschatological reality in which "the nations will bring their glory and honor" into the new creation (Rev 21:26). No such almugwood has been seen since: the uniqueness of the Solomonic era is the OT\'s closest approximation of the world made fully right, now forever past.</p>',
    "12": '<p>A shadow: the almugwood made into supports (<em>misʿādôt</em>, railings or steps) for the temple and into instruments of praise — lyres and harps for the musicians. Creation\'s material beauty (wood from distant lands) is transfigured into instruments of worship. This foreshadows the new creation in which all things find their ultimate purpose in the praise of God: "And every creature in heaven and on earth and under the earth and in the sea, and all that is in them, saying, \'To him who sits on the throne and to the Lamb be blessing and honor and glory and might forever and ever\'" (Rev 5:13).</p>',
    "13": '<p>A shadow: Solomon gives the queen "everything she desired and asked for, in addition to all that he gave her out of his royal generosity" (<em>kᵉyaḏ hammelek šᵉlōmōh</em>, "according to the hand of King Solomon"). The king\'s generosity exceeds the visitor\'s request — this is the OT pattern of divine abundance. Jesus makes this the pattern of the Father\'s giving: "Ask, and it will be given to you; seek, and you will find" (Matt 7:7); and Paul extends it: "He who did not spare his own Son but gave him up for all of us, how will he not also with him graciously give us all things?" (Rom 8:32). Solomon\'s open-handedness shadows the generosity of the one greater than Solomon.</p>',
    "14": '<p>A shadow: 666 talents of gold arriving to Solomon in a single year — the numeric peak of Solomonic wealth. The number represents the apex of earthly royal glory, and its very splendor conceals its fragility: this is the moment before the fall narrated in ch. 11. The weight of gold is not given to identify Solomon with Revelation\'s beast (the NT contextualizes 666 differently, Rev 13:18); it marks rather the outer limit of what the greatest human king could accumulate. What Solomon could collect in weight of gold, Christ offers in imperishable currency: "the riches of his grace" (Eph 1:7) that no accounting can exhaust.</p>',
    "15": '<p>A shadow: the enumeration of Solomon\'s income from merchants, traders, kings of Arabia, and governors of the land. The breadth of the tribute network foreshadows the universal tribute described in Ps 72:10-11: "May the kings of Tarshish and of the coastlands render him tribute; may the kings of Sheba and Seba bring gifts! May all kings fall down before him, all nations serve him!" — a psalm read messianically in the NT tradition. Solomon\'s tributary network is the historical shadow of the eschatological reality.</p>',
    "16": '<p>A shadow: the two hundred large shields of hammered gold placed in the House of the Forest of Lebanon. The royal armory of gold — weapons that could never actually be used in battle (they are display objects) — represents the ceremonial magnificence of the Solomonic kingdom. The contrast with Christ\'s kingship is illuminating: his instruments of conquest are not gold shields but weakness and the cross (1 Cor 1:25), weapons that actually win the decisive battle against sin and death (Col 2:15).</p>',
    "17": '<p>A shadow: three hundred smaller shields of hammered gold, also placed in the House of Lebanon. The duplication of royal golden shields underscores the ceremonial nature of Solomonic glory — magnificence that is primarily visual. The NT counterpart to royal display is not ornamentation but mission: Christ equips his people with the "full armor of God" (Eph 6:10-17), which is functional rather than decorative, designed for actual combat against spiritual powers.</p>',
    "18": '<p>A shadow: the great ivory throne overlaid with the finest gold. The throne of the Davidic king is the OT\'s earthly instantiation of the divine throne — a human approximation of the heavenly reality described in Isaiah 6, Ezekiel 1, and Daniel 7. The Solomonic throne\'s magnificence (ivory + gold, lions, six steps) shadows the throne described in Rev 4-5 and the promise to believers to share Christ\'s throne: "The one who conquers, I will grant him to sit with me on my throne, as I also conquered and sat down with my Father on his throne" (Rev 3:21).</p>',
    "19": '<p>A shadow: the six-stepped throne with two lions beside the armrests — the royal lion flanking the king. The lion as royal emblem connects to the tribal blessing of Judah ("a lion\'s cub," Gen 49:9) and to Christ as "the Lion of the tribe of Judah" (Rev 5:5). Solomon\'s lion-flanked throne is the Davidic-dynasty shadow of the Lamb who is also the Lion — the enthroned ruler before whom every knee will bow (Phil 2:10).</p>',
    "20": '<p>A shadow: twelve lions standing on the six steps, six on each side — "nothing like it had been made in any kingdom." The twelve lions may echo the twelve tribes of Israel, surrounding the king who rules over all Israel. The uniqueness of the Solomonic throne ("nothing like it") prefigures the absolute uniqueness of Christ\'s throne — the only throne before which all creation will one day stand (Rev 20:11-12).</p>',
    "21": '<p>A shadow: all Solomon\'s drinking cups are gold; all vessels in the House of the Forest of Lebanon are pure gold. Silver is not considered worth anything in Solomon\'s day. The currency devaluation caused by Solomon\'s wealth is a shadow of the eschatological reversal where the former costly things of earth become commonplace in the new creation (Rev 21:21, "the street of the city was pure gold"). What Solomon achieves economically for a generation, the new Jerusalem establishes permanently for eternity.</p>',
    "22": '<p>A shadow: the fleet of Tarshish ships returning every three years with gold, silver, ivory, apes, and peacocks — the exotic wealth of the whole world flowing to Solomon\'s court. Ps 72:10 ("May the kings of Tarshish and of the coastlands render him tribute") is the messianic psalm that applies this Tarshish-tribute pattern to the ideal Davidic king. The Solomonic reality partially fulfills Ps 72 during his reign; the full fulfillment awaits the reign of David\'s greater son.</p>',
    "23": '<p>A type: "King Solomon surpassed all the kings of the earth in riches and wisdom." This is the high-water mark of Davidic-line glory, and Jesus explicitly identifies himself as what Solomon points to: "something greater than Solomon is here" (Matt 12:42). The superlative language (<em>hāyāh gedôl</em>) is picked up and exceeded in the NT\'s christological superlatives — "the name above every name" (Phil 2:9), "far above all rule and authority" (Eph 1:21), "the firstborn over all creation" (Col 1:15). Solomon\'s greatness among kings is a type of Christ\'s greatness over all things.</p>',
    "24": '<p>A type: "All the peoples of the earth sought an audience with Solomon to hear the wisdom that God had placed in his heart." The gathering of all peoples before the wise king is the OT prototype of the eschatological gathering before Christ. The wisdom "placed in his heart" by God (H3820 + H430) is a human impartation, temporary and derived; Col 2:3 identifies Christ as the one in whom "are hidden all the treasures of wisdom and knowledge" — not placed in him but inherent in him as the eternal Word (John 1:1-3). What Solomon offers by divine grant, Christ is by nature.</p>',
    "25": '<p>A shadow: year after year every visitor brings gifts — silver, gold, garments, weapons, spices, horses, mules. The annual pilgrimage tribute to Solomon anticipates the eschatological pilgrimage of the nations to the Davidic Messiah. Ps 72:15 ("May prayer be made for him continually, and blessings invoked for him all the day! May there be abundance of grain in the land... and people be blessed in him, all nations call him blessed!") reads the Solomonic pattern as a messianic portrait. The annual tribute shadow reaches its fulfillment in Rev 21:24-26.</p>',
    "26": '<p>A shadow: Solomon accumulates 1,400 chariots and 12,000 horsemen. The Torah\'s law for kings (Deut 17:16) explicitly forbids the king to "multiply horses for himself or cause the people to return to Egypt in order to acquire many horses." Solomon violates this command directly (v28 makes the Egypt connection explicit). The accumulated chariots and horsemen are the beginning of the Torah-violation pattern that culminates in v1-8 of ch. 11. The ideal king of Israel is not to trust in horses (Ps 33:17; Isa 31:1); the shadow of Christ\'s kingship is power made perfect in weakness (2 Cor 12:9), not military accumulation.</p>',
    "27": '<p>A shadow: silver made as common as stones in Jerusalem, cedars as plentiful as sycamore figs. The transformation of precious materials into commonplace abundance is the OT picture of eschatological prosperity — Isaiah 60:17 ("Instead of bronze I will bring gold, and instead of iron I will bring silver"). Solomon\'s economic transformation of Jerusalem for one generation shadows the permanent transformation of the new creation. But what Solomon achieves by accumulation, the new creation achieves by the gift of God\'s presence (Rev 21:23, "the city has no need of sun... for the glory of God gives it light").</p>',
    "28": '<p>A shadow: Solomon\'s horses imported from Egypt and Kue. The return to Egypt for horses is an explicit violation of Deut 17:16. The king who should model trust in YHWH over military power (Ps 20:7, "Some trust in chariots and some in horses, but we trust in the name of the LORD our God") turns to Egypt instead. This verse marks the narrative\'s quiet turn: Solomon begins to look less like the ideal covenant king and more like a standard ancient Near Eastern monarch. The contrast with Christ is sharp — Christ refused to call down twelve legions of angels (Matt 26:53) and entered Jerusalem on a donkey, not a war horse (Matt 21:5; Zech 9:9).</p>',
    "29": '<p>A shadow: the chariot trade routes — Egypt to Hittites and Aram, 600 shekels of silver per chariot, 150 per horse. Solomon as international arms trader is as far from the Deuteronomic ideal as it is possible to be. The king who should trust in YHWH\'s name (Deut 17:18-20, reading the Torah daily to humble himself) is instead running a weapons business with Israel\'s traditional enemies. The corruption of Solomonic kingship, fully revealed in ch. 11, is already audible here. Christ\'s economy inverts this: he does not trade in weapons of war but gives the "sword of the Spirit" freely (Eph 6:17).</p>'
  },
  "11": {
    "1": '<p>A revelation of God: Solomon\'s love (<em>ʾāhaḇ</em>, H157) for many foreign women stands against the covenant love YHWH has commanded — "you shall love the LORD your God with all your heart" (Deut 6:5). The king who was supposed to embody Israel\'s covenant fidelity is defined by his love for those whom the Torah warned against. The failure of the human king at the point of his heart\'s loyalty — loving what he should not love — is the theological problem that only a king whose heart is constitutively aligned with the Father can solve. "He who did not know sin became sin for us" (2 Cor 5:21): Christ succeeds precisely at the point where Solomon catastrophically fails.</p>',
    "2": '<p>A revelation of God: "YHWH had told the Israelites, \'You must not intermarry with them, nor they with you, for they will surely turn your hearts after their gods.\'" The warning was specific, public, and covenantally grounded. Solomon\'s disobedience is not a mistake born of ignorance but a choice against known divine instruction. This reveals God\'s covenant seriousness: the warnings attached to covenant relationship are not rhetorical but predictive. The NT carries the principle forward: "Do not be unequally yoked with unbelievers" (2 Cor 6:14) and "the love of the world is enmity with God" (Jas 4:4). Solomon\'s story is the canonical illustration of what these warnings prevent.</p>',
    "3": '<p>A revelation of God: 700 wives of royal standing and 300 concubines — the explicit violation of Deut 17:17 ("he must not multiply wives for himself, lest his heart turn away"). The Torah\'s law for kings was written for this precise scenario; Solomon\'s accumulation of women mirrors his accumulation of gold and horses as a three-fold violation of the Deuteronomic royal ideal (Deut 17:14-20). The correlation between the multiplication of wives and the turning of the heart (<em>wayyaṭṭû nāšāyw ʾet libbô</em>) is explicit in the text. The heart — the locus of covenant loyalty — is turned by the accumulation that the Torah forbade. Christ\'s covenant fidelity is the counter-pattern: his heart is never divided, his loyalty never purchased or seduced.</p>',
    "4": '<p>A revelation of God: "As Solomon grew old, his wives turned his heart after other gods, and his heart was not fully devoted (<em>šālēm</em>, whole/complete) to the LORD his God, as the heart of his father David had been." The <em>lēḇāḇ šālēm</em> — the whole, undivided heart — is the Deuteronomic standard for covenant faithfulness (Deut 6:5; 1 Kgs 8:61). Solomon\'s heart is found deficient at old age, after all his wisdom, after the temple dedication, after two divine appearances. The failure reveals that wisdom, worship, and divine encounter do not guarantee heart-wholeness. Only the one who is the divine Word incarnate — whose will is perfectly conformed to the Father\'s at every point (John 6:38; Heb 10:7) — can offer the <em>lēḇāḇ šālēm</em> that the covenant requires.</p>',
    "5": '<p>A revelation of God: Solomon follows Ashtoreth the goddess of the Sidonians and Milcom the detestable god of the Ammonites. The wisdom king whose temple celebrated YHWH\'s unique glory (1 Kgs 8:23, "there is no God like you in heaven above or on earth beneath") now pays homage to the gods of Israel\'s neighbors. The trajectory from temple-builder to idol-follower reveals the tragic insufficiency of even the greatest human achievement in honoring God. No temple built with human hands and no wisdom derived from human intellect guarantees ongoing fidelity. The NT response is the indwelling Spirit (1 Cor 3:16-17; 6:19): the only temple that will not be defiled because its architect and inhabitant is God himself.</p>',
    "6": '<p>A revelation of God: "Solomon did evil in the LORD\'s sight and did not follow the LORD completely (<em>millēʾ ʾaḥᵃrê</em>, did not fill up / go fully after) as his father David had done." The narrator\'s verdict uses covenantal language: following YHWH completely (<em>millēʾ ʾaḥᵃrê</em>) is the OT\'s expression for wholehearted covenant fidelity. David, for all his sins, is the standard; Solomon falls short of even the David-standard. The NT\'s standard is higher still — "Be perfect, as your heavenly Father is perfect" (Matt 5:48) — and is only achievable through Christ\'s imputed righteousness and the Spirit\'s transformative work.</p>',
    "7": '<p>A revelation of God: Solomon builds a high place for Chemosh (Moab) and for Molech (Ammon) on the hill east of Jerusalem — the Mount of Olives, directly facing the temple. The placement is theologically devastating: the site of idolatrous sacrifice (Molech worship involved child sacrifice) is set in direct visual confrontation with the house of YHWH. The Mount of Olives will later become the site of Christ\'s prayer in Gethsemane (Luke 22:39) and his ascension (Acts 1:12) — a redemptive reoccupation of the same hill. The NT\'s repeated use of the Mount of Olives in the passion narrative may carry an implicit echo of this reversal: where Solomon established Gentile abominations, Christ offers his perfect obedience to the Father.</p>',
    "8": '<p>A revelation of God: "He did the same for all his foreign wives, who burned incense and offered sacrifices to their gods." The temple system, designed to be the exclusive locus of Israel\'s worship, is now surrounded by competing shrines all within Solomon\'s purview. The compromise is total. What the temple was built to embody — the exclusive claim of YHWH on his people\'s worship — is undone by the one who built it. The lesson the NT draws: no human institution, however divinely ordered, automatically guarantees the holiness of its builders. Only the living presence of the Spirit maintains the purity of the temple that is Christ\'s body (1 Cor 3:16-17).</p>',
    "9": '<p>A revelation of God: "The LORD was angry (<em>wayyitʾanap</em>, H599 — a strong term for divine anger) with Solomon because his heart had turned (<em>nāṭāh libbô</em>) from YHWH the God of Israel, who had appeared to him twice." The divine anger is presented as a covenant response to a specific, aggravated covenant violation: YHWH had appeared to Solomon personally (ch. 3 and ch. 9) — greater revelation entails greater accountability. The NT carries this principle: "For everyone to whom much was given, much will be required" (Luke 12:48); and Heb 10:26-29 warns that deliberate sin after receiving the knowledge of the truth incurs severer judgment. Solomon\'s privileged access to divine revelation makes his apostasy the more culpable.</p>',
    "10": '<p>A revelation of God: "He had warned him expressly about this very thing — not to follow other gods. But Solomon did not keep the LORD\'s command." The word <em>ṣiwwāh</em> (commanded, H6680) is the standard verb for covenant obligation — what YHWH commands, Israel is bound to obey. Solomon\'s failure is not ignorance but disobedience against explicit divine command. The NT\'s characterization of sin as lawlessness (<em>anomia</em>, 1 John 3:4) — violation of known divine standard — is grounded in narratives exactly like this one. Christ\'s perfect obedience (<em>hupakoē</em>, Rom 5:19) is the reversal of Solomon\'s disobedience: "as by the one man\'s disobedience the many were made sinners, so by the one man\'s obedience the many will be made righteous."</p>',
    "11": '<p>A revelation of God and a shadow: "I will certainly tear the kingdom from you and give it to one of your servants." The covenant consequence is judicial and declarative: YHWH is the one who gives and takes kingship. The term <em>qāraʿ</em> (tear, H7167) — the same word used in v30 for Ahijah\'s tearing of the garment — will become the controlling image of the chapter. The transfer of the kingdom from Solomon\'s house is not a defeat of YHWH\'s purposes but a demonstration of them: the Davidic covenant\'s persistence through and beyond the Solomonic failure is itself the proof of God\'s sovereign faithfulness. The NT reveals that God uses human failure as the occasion of redemptive advance: the division of the kingdom leads ultimately to the exile that produces the diaspora through which the gospel spreads (Acts 8:1).</p>',
    "12": '<p>A revelation of God: "For the sake of your father David I will not do this during your lifetime. I will tear it away from your son." The Davidic covenant creates a reserve of grace that persists through Solomon\'s failure: judgment is deferred, not cancelled. This pattern of deferred-but-certain judgment out of covenant loyalty to prior faithfulness is consistent throughout Kings (see also 15:4; 2 Kgs 8:19). The NT\'s ultimate expression of this pattern is the cross itself: the judgment that human sin deserved was not cancelled but absorbed — into Christ — so that mercy could be extended. God\'s deference toward Solomon points to God\'s ultimate deferral of judgment through the substitution of his Son.</p>',
    "13": '<p>A revelation of God: "Yet I will not tear away the entire kingdom. I will give one tribe to your son, for the sake of my servant David and for the sake of Jerusalem, which I have chosen." The preservation of one tribe is YHWH\'s covenant minimum — enough to keep the Davidic line alive and the Jerusalem temple standing. This is not divine minimalism but divine faithfulness operating at the point of maximum human failure. The phrase "for the sake of my servant David" (<em>bᵃʿăḇûr dāwîḏ ʿaḇdî</em>) becomes the formula for grace that survives moral collapse. The NT\'s "for the sake of Christ" (<em>dia Christon</em>, Eph 4:32; Col 3:13) carries the identical structure: what the covenant person achieved by faithfulness becomes the ground on which others receive mercy they have not earned.</p>',
    "14": '<p>A revelation of God: "The LORD raised up (<em>wayyāqem YHWH</em>) an adversary (<em>śāṭān</em>) against Solomon: Hadad the Edomite." The word <em>śāṭān</em> (H7854) — "adversary" — is used here in its original, non-demonic sense: an enemy raised up by God as a covenant instrument of discipline. The same word describes the accuser in Job 1-2. YHWH\'s sovereignty over adversarial forces — his ability to raise them against the disobedient and to use them for covenant purposes — is the OT foundation for the NT\'s doctrine that even demonic opposition is bounded by divine permission (Job 1:12; Luke 22:31-32; 1 Cor 10:13). Christ confronts and defeats the ultimate <em>śāṭān</em> (Matt 4:10; Rev 20:10).</p>',
    "15": '<p>A shadow: when David had been in Edom, Joab had struck down every male in Edom (cf. Ps 60:1-2, associated with this campaign). David\'s military legacy creates the adversary Solomon will face. The consequences of past actions — even justified covenant warfare — ripple forward into subsequent generations. This is the OT\'s patient historical vision: causes have effects across time. The NT\'s eschatological patience ("the Lord is not slow... but patient toward you," 2 Pet 3:9) and the doctrine of the sins of the fathers (Exod 20:5) both assume this same long temporal arc that culminates in Christ\'s final reckoning of all things (Acts 17:31).</p>',
    "16": '<p>A shadow: Joab and all Israel remained six months in Edom until every male was killed — a total military campaign. The completeness of David\'s suppression of Edom created the conditions for Hadad\'s survival as refugee and eventual adversary. History\'s "solutions" that eliminate one problem often create future ones. Only the eschatological judgment of Christ provides the final, non-cyclical resolution: "He must reign until he has put all his enemies under his feet. The last enemy to be destroyed is death" (1 Cor 15:25-26).</p>',
    "17": '<p>A shadow: Hadad escapes as a small boy to Egypt — the same Egypt that sheltered Joseph (Gen 39-47) and received the infant Jesus (Matt 2:14-15). Egypt functions in biblical narrative as a recurring place of refuge from those who would kill God\'s appointed (Joseph, Moses, the infant Christ). The pattern is not coincidental: Matthew\'s "out of Egypt I called my son" (Matt 2:15, citing Hos 11:1) explicitly maps the Jesus-to-Egypt-and-back journey onto Israel\'s founding narrative, and this same shadow falls over Hadad\'s escape.</p>',
    "18": '<p>A shadow: Hadad\'s journey — Midian, Paran, Egypt — echoes the wilderness geography of Israel\'s own history. Pharaoh\'s reception of Hadad (giving him a house, land, and sustenance) parallels the Egyptian reception of Jacob\'s family (Gen 45:18; 47:11). The recurring pattern of YHWH\'s covenant purposes advancing through unexpected geographical sojourns and foreign hospitality will reach its apex in the holy family\'s flight to and return from Egypt (Matt 2:13-21).</p>',
    "19": '<p>A shadow: Hadad wins such favor with Pharaoh that he receives the sister of the queen as wife. The depth of Hadad\'s Egyptian integration — royal household, wife from the court — establishes him as a credible adversary capable of challenging Solomon. The narrative\'s quiet preservation of this Edomite thread through the Solomonic era is an instance of the OT\'s patient story of how YHWH\'s covenant purposes advance even through the adversaries he raises up. The NT counterpart: even the enemies of the gospel serve its advance (Phil 1:12).</p>',
    "20": '<p>A shadow: Genubath, Hadad\'s son, grows up among Pharaoh\'s own sons — an Edomite in the Egyptian court. The child of Israel\'s adversary raised in Israel\'s former slave-house, poised to become a future threat, is a micro-narrative of the complex entanglement of nations that God uses for his own purposes. The wisdom literature\'s question ("Who can know the thoughts of God?" Isa 40:13; Rom 11:34) is embedded in these narratives of extraordinary circumstance: all of this — Hadad\'s survival, Egyptian marriage, son in Pharaoh\'s court — is YHWH\'s preparation of a covenant instrument.</p>',
    "21": '<p>A shadow: when Hadad hears that David and Joab are dead, he asks to return home. The deaths of his enemies free him to pursue his purpose. The interaction between personal opportunity and divine orchestration is characteristic of OT narrative: Hadad acts from self-interest, but YHWH has raised him up (v14) for a larger purpose. The NT\'s providence theology (Rom 8:28, "all things work together for good") is not the absence of human motivation but God\'s sovereign direction of genuinely motivated human actions toward his purposes.</p>',
    "22": '<p>A shadow: Hadad\'s "nothing — but please, let me go." The adversary\'s determination to return cannot be deterred by comfort; the covenant purpose that raised him up (v14) is stronger than Egyptian prosperity. The certainty of God\'s instruments fulfilling their purpose runs throughout biblical narrative — Jonah cannot outrun his mission (Jon 1:3-17), Paul cannot remain in Damascus once called to the Gentiles (Acts 9:15-25), and the adversaries of God\'s people accomplish the discipline YHWH intends (Hab 1:6). Only Christ himself has full sovereignty over when and how divine purposes are accomplished.</p>',
    "23": '<p>A revelation of God: "God also raised up (<em>wayyāqem ʾĕlōhîm</em>) another adversary against Solomon: Rezon son of Eliada." The second adversary is introduced with the same sovereign verb: YHWH raises up adversaries as instruments of covenant discipline. The repetition (Hadad in v14, Rezon here) emphasizes the pattern: disobedience multiplies adversaries; the covenant curses of Deuteronomy 28 are beginning their systematic fulfillment. The NT\'s doctrine of divine discipline — "For the Lord disciplines the one he loves, and chastises every son whom he receives" (Heb 12:6, citing Prov 3:11-12) — has this long OT history of God-raised adversaries as its background.</p>',
    "24": '<p>A shadow: Rezon gathers men around him after David destroys Hadadezer\'s forces, goes to Damascus, and becomes king there. The collapse of one Aramean power structure (Hadadezer\'s) creates the opening for a new, adversarial Aramean state (Rezon\'s Damascus). The pattern recurs throughout OT history: destroyed threats generate successor threats. This is not divine failure but covenant pedagogy — the instability of the present age will only end when the one who "disarmed the rulers and authorities and put them to open shame, triumphing over them in him" (Col 2:15) brings the final peace.</p>',
    "25": '<p>A shadow: Rezon is a persistent adversary throughout Solomon\'s lifetime — combined with Hadad, the two threats bracket the Solomonic era. The peaceful interlude of Solomon\'s early reign (1 Kgs 4:24-25, "Solomon had peace on all sides") is over. The fragility of earthly peace — dependent on the faithfulness of the human king who maintains it — contrasts with the peace that Christ gives: "not as the world gives" (John 14:27), grounded not in military balance but in the reconciliation of humanity to God (Rom 5:1; Eph 2:14-17).</p>',
    "26": '<p>A shadow: Jeroboam son of Nebat, an Ephraimite and Solomon\'s own official, also rebels. The third adversary is internal — not an Edomite or Aramean outsider but a capable Israelite insider whom Solomon himself had promoted. The structure of this chapter is deliberately comprehensive: external enemies (Hadad, Rezon) and internal betrayal (Jeroboam) simultaneously close in on the Solomonic kingdom. The Davidic ideal requires a king whose kingdom is at peace from without and whose servants are loyal within. Only the messianic king of Ps 72 and Isa 11 fulfills both conditions permanently.</p>',
    "27": '<p>A shadow: the background to Jeroboam\'s rebellion is Solomon\'s building program — the Millo and the repair of David\'s city wall. The construction that secured the capital also generated the resentment (forced labor, cf. ch. 5) that produced the rebel. Solomon\'s greatest achievement (the city) carries the seeds of its own undoing. The NT\'s paradox is the inverse: Christ\'s apparent defeat (the cross) is the instrument of ultimate victory (resurrection). What appears to destroy the Davidic project in fact establishes it permanently (Acts 2:23-24).</p>',
    "28": '<p>A shadow: Jeroboam is a capable (<em>gibbôr ḥayil</em>, a man of valor/ability) young man whom Solomon himself places over the forced labor of the house of Joseph. Solomon creates his own replacement — the king raises up the instrument of his own judgment. This irony is a recurring biblical pattern: God often uses the gifts and initiative of the very people whom the powerful have elevated and exploited. Joseph, raised to power by Pharaoh, becomes Israel\'s deliverer; David, promoted by Saul, replaces him. The NT pattern: Jesus is "elevated" on the cross by those who oppose him, and thereby defeats them (Col 2:13-15).</p>',
    "29": '<p>A revelation of God: Ahijah the Shilonite meets Jeroboam on the road and performs a prophetic sign-act — wearing a new garment. The choice of a new garment is significant: the newness (<em>ḥādāš</em>) of the cloak mirrors the newness of what is about to be announced — a new dynastic arrangement. Prophetic sign-acts in the OT are not mere illustrations; they are performative declarations that set in motion what they signify (cf. Jer 19:10-11; Ezek 4). The tearing of the garment that follows is a enacted word that will not return void (cf. Isa 55:11). The NT\'s ultimate "new thing" (<em>kainós</em>) is the new covenant (Jer 31:31; Luke 22:20) established by the one who makes "all things new" (Rev 21:5).</p>',
    "30": '<p>A revelation of God: Ahijah tears the new garment into twelve pieces. The violence of the act — a new garment torn — makes visible what disobedience does to the covenant unity of Israel. The twelve pieces correspond to the twelve tribes, now about to be redistributed. Sign-acts in the prophetic tradition enact the divine word at the level of the body and the material: the torn garment is what YHWH will do to the kingdom. The NT\'s enacted word is the broken body of Christ — "this is my body, broken for you" (1 Cor 11:24) — which, unlike the torn kingdom, becomes the instrument of unity rather than division: "one body, one Spirit" (Eph 4:4).</p>',
    "31": '<p>A direct prophecy and type: "Take ten pieces for yourself. For this is what the LORD, the God of Israel, says: I am tearing the kingdom from Solomon\'s hand and giving you ten tribes." The tearing of the kingdom is YHWH\'s direct action (<em>ʾănî qōrēaʿ</em>, I am tearing), with Ahijah\'s sign-act as its enactment. Jeroboam\'s commission parallels David\'s original anointing (1 Sam 16:13) and prefigures Christ\'s reception of all authority: "All authority in heaven and on earth has been given to me" (Matt 28:18). As Jeroboam receives ten tribes from the one who held them, so the risen Christ receives all nations from the Father (Ps 2:8).</p>',
    "32": '<p>A revelation of God: "He will keep one tribe — for the sake of my servant David and for the sake of Jerusalem, the city I have chosen from all the tribes of Israel." The divine election of both person (David) and place (Jerusalem) is the covenant\'s double anchor. Neither collapses under the weight of Solomon\'s failure. The perseverance of both through the division narrative is the OT\'s demonstration that divine election does not depend on human performance. The NT\'s "in Christ" language carries the same structure: "he chose us in him before the foundation of the world" (Eph 1:4) — election grounded in the Elect One, not in the elect people\'s merit.</p>',
    "33": '<p>A revelation of God: "Because they have abandoned me and worshipped Ashtoreth... Chemosh... Milcom. They have not walked in my ways or done what is right in my eyes, nor kept my statutes and ordinances as David his father did." The covenant indictment is comprehensive: the verbs are communal (they, plural) — Solomon\'s apostasy is not purely individual but national in its effect. The king\'s heart is the nation\'s covenant representative. This is the OT\'s basis for the NT\'s federal theology: one representative\'s failure (Adam) implicates many; one representative\'s faithfulness (Christ) justifies many (Rom 5:12-19). The Davidic standard (v33b) set for Israel\'s kings is the shadow of the standard Christ alone meets on behalf of all.</p>',
    "34": '<p>A revelation of God: "But I will not take the whole kingdom from him. I will keep him as ruler for the rest of his life, for the sake of my servant David whom I chose, because David kept my commandments and statutes." David\'s covenant-keeping provides the covering that extends grace to the disobedient Solomon. The substitutionary structure is explicit: David\'s merits are the ground of Solomon\'s continuation in office. The NT\'s explicit claim is the same logic extended infinitely: Christ\'s perfect covenant-keeping provides the covering for all who are united to him by faith (2 Cor 5:21; Phil 3:9). Solomon benefits from David\'s righteousness covenantally; the believer benefits from Christ\'s righteousness infinitely.</p>',
    "35": '<p>A revelation of God: "I will take the kingdom from his son\'s hand and give it to you — ten tribes." The transfer is surgical: one son loses ten-twelfths of his inheritance, not because of his personal sin (he has not yet sinned) but because of his father\'s. The inter-generational nature of covenant consequences (Exod 20:5) is uncomfortable but honest: communities and dynasties bear the weight of their leaders\' choices. The NT\'s resolution is the one who bears the weight of all the covenant failures of all the dynasties in his own body, so that those united to him receive the full inheritance rather than a fraction (Col 1:12; Heb 9:15).</p>',
    "36": '<p>A direct promise: "I will give his son one tribe, so that my servant David may always have a <em>nîr</em> (lamp/dominion, H5216) before me in Jerusalem, the city where I have chosen to put my name." The <em>nîr lᵉdāwîḏ</em> — a lamp for David — is a covenantal formula for the perpetuation of the Davidic dynasty (cf. 1 Kgs 15:4; 2 Kgs 8:19; Ps 132:17: "There I will make a horn sprout for David; I have prepared a lamp for my anointed"). In Luke 1:69 Zechariah declares that God "has raised up a horn of salvation for us in the house of his servant David" — this is the lamp promise fulfilled. Christ is the promised <em>nîr lᵉdāwîḏ</em>: the light that the Davidic covenant preserved through every crisis until it blazed fully in the one who says "I am the light of the world" (John 8:12).</p>',
    "37": '<p>A shadow: "I will take you, and you will reign over all that your heart desires, and you will be king over Israel." Jeroboam\'s commission follows the pattern of David\'s: a capable man from an unexpected tribe elevated by divine choice to kingship. The parallel is deliberate and sobering — Jeroboam is given the same opportunity David had, and will fail where David succeeded. The king who reigns "over all that his heart desires" is ultimately the one whose heart desires perfectly what God desires. Ps 40:8 (cited in Heb 10:7 as Christological): "I delight to do your will, O my God; your law is within my heart." Only Christ\'s heart-desire is fully aligned with the Father\'s; only his reign is therefore unending.</p>',
    "38": '<p>A shadow: "If you obey all I command you, walk in my ways, and do what is right in my sight... then I will be with you. I will build you a lasting dynasty as I did for David, and I will give you Israel." The conditional structure — if you obey, then I will establish — is the standard Deuteronomic covenant formula. Jeroboam will fail this condition immediately (1 Kgs 12:28-30: golden calves). The permanent dynasty promised conditionally to Jeroboam is granted unconditionally to Christ: "Of the increase of his government and of peace there will be no end, on the throne of David and over his kingdom, to establish it and to uphold it" (Isa 9:7). The conditional promise points toward the one who meets the condition perfectly and therefore receives the unconditional fulfillment.</p>',
    "39": '<p>A shadow: "I will humble (<em>ʾᵃʿanneh</em>, H6031) the descendants of David because of this — but not forever (<em>wᵉlōʾ kol-hayyāmîm</em>)." The "not forever" is one of the OT\'s most quietly significant phrases. The humiliation of the Davidic line is real — through the divided kingdom, the Assyrian threat, the Babylonian exile, the return as Persian subjects — but it is bounded. The eschatological reservation ("not forever") points beyond every historical humiliation to the restoration YHWH will accomplish. Paul applies the same logic to Israel\'s current partial hardening: "a partial hardening has come upon Israel, until the fullness of the Gentiles has come in. And in this way all Israel will be saved" (Rom 11:25-26). The "not forever" of 1 Kgs 11:39 is the OT root of the "until" of Rom 11:25.</p>',
    "40": '<p>A shadow: Solomon tries to kill Jeroboam, who flees to Egypt. The anointed king trying to destroy the one whom the prophet has designated is the Solomonic repetition of Saul\'s pursuit of David (1 Sam 19-26), which is itself repeated in Herod\'s slaughter of the innocents (Matt 2:13-16). The pattern of established power attempting to destroy the divinely chosen successor is a recurrent OT structure that reaches its apex in the crucifixion of Christ — "the rulers of the world... would not have crucified the Lord of glory" (1 Cor 2:8), yet in doing so they accomplished the very purpose God had ordained (Acts 2:23; 4:27-28).</p>',
    "41": '<p>A shadow: "As for the rest of Solomon\'s acts — all he did and his wisdom — are they not written in the Book of the Acts of Solomon?" The narrator\'s reference to a now-lost source is an acknowledgment that the canonical text does not capture everything. The wisdom and acts of Solomon that exceeded what is recorded stand as a reminder that even the fullest human achievement is only partially preserved. The NT\'s equivalent: "Now Jesus did many other signs in the presence of the disciples, which are not written in this book" (John 20:30); "the world itself could not contain the books that would be written" (John 21:25). Solomon\'s unrecorded acts are finite; Christ\'s unrecorded works are inexhaustible.</p>',
    "42": '<p>A shadow: "Solomon reigned in Jerusalem over all Israel for forty years." The forty years mirrors other significant OT forty-year periods: the wilderness wandering (Deut 8:2-4), David\'s reign (2 Sam 5:4), the oppression periods in Judges. The number carries a sense of completeness-in-testing. Solomon\'s forty-year reign is complete in itself and complete in its typological function — the greatest human king has reigned; he has failed; the stage is set for the one who will reign forever. The "forty days" of Jesus\'s wilderness testing (Matt 4:1-11) deliberately echoes Israel\'s forty years; Jesus succeeds where Israel (and Solomon) failed.</p>',
    "43": '<p>A shadow: "Then Solomon rested with his ancestors and was buried in the city of his father David. And his son Rehoboam succeeded him as king." The formula "rested with his ancestors" is the standard burial notice for Israel\'s kings — they sleep, awaiting the resurrection. The Davidic succession continues despite Solomon\'s failure (Rehoboam, not Jeroboam, inherits Jerusalem and the one tribe), because YHWH\'s covenant with David does not collapse with Solomon\'s sin. The "rested with ancestors" formula points forward to the one who also "rested" in death but did not remain — whose resurrection broke the pattern that every previous Davidic king had established (Acts 2:29-32: "David both died and was buried... he foresaw and spoke about the resurrection of the Christ, that he was not abandoned to Hades, nor did his flesh see corruption").</p>'
  }
}

